import{c as a,Q as d,j as t,m as o}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Модели анализа","description":"","frontmatter":{},"headers":[],"relativePath":"ru/models.md","filePath":"ru/models.md","lastUpdated":1780022874000}'),c={name:"ru/models.md"};function s(i,e,l,n,r,h){return d(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="модели-анализа" tabindex="-1">Модели анализа <a class="header-anchor" href="#модели-анализа" aria-label="Permalink to &quot;Модели анализа&quot;">​</a></h1><p>Эта страница описывает модели, лежащие в основе каждого семейства анализа: что представляет собой каждая модель, что она выдаёт и как приложение использует и сохраняет её результат. Используйте её вместе с <a href="./analysis.html">Анализ</a>, где основное внимание уделено тому, <em>какой</em> проход запускать первым, и <a href="./search-and-tags.html">Поиск и теги</a>, где описано, как выполняется поиск по результатам.</p><p>Весь анализ моделей работает по принципу database-first: он читает аудио и записывает результаты только в SQLite. Он не изменяет аудиофайлы. Единственный явный путь записи в аудиофайлы — это сохранение жанровых тегов MAEST, описанное в <a href="./search-and-tags.html">Поиск и теги</a>.</p><h2 id="сводка-по-моделям" tabindex="-1">Сводка по моделям <a class="header-anchor" href="#сводка-по-моделям" aria-label="Permalink to &quot;Сводка по моделям&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Модель</th><th>Идентификатор / чекпойнт</th><th>Что выдаёт</th><th>Embedding key</th><th>Устройство</th><th>Требует</th></tr></thead><tbody><tr><td>Sonara</td><td><code>sonara.analyze_file</code></td><td>Объяснимые признаки плейлиста</td><td>н/д</td><td>CPU</td><td><code>sonara</code></td></tr><tr><td>MAEST</td><td><code>discogs-maest-30s-pw-129e-519l</code> (<code>maest-infer</code>)</td><td>Жанровые метки + embedding</td><td><code>maest</code></td><td><code>auto</code>/<code>cpu</code>/<code>cuda</code></td><td><code>ml</code></td></tr><tr><td>MERT</td><td><code>m-a-p/MERT-v1-95M</code></td><td>Audio-to-audio embedding</td><td><code>mert</code></td><td><code>auto</code>/<code>cpu</code>/<code>cuda</code></td><td><code>ml</code></td></tr><tr><td>CLAP</td><td><code>music_audioset_epoch_15_esc_90.14.pt</code> (LAION)</td><td>Аудио- и текстовые embeddings</td><td><code>clap</code></td><td><code>auto</code>/<code>cpu</code>/<code>cuda</code></td><td><code>ml</code></td></tr></tbody></table><p>Признаки Sonara хранятся в <code>metadata_json.sonara_features</code>. Векторы MERT, MAEST и CLAP хранятся в таблице <code>embeddings</code> под своим embedding key. Полную схему хранения см. в разделе <a href="./database.html">База данных</a>.</p><p>Выбор устройства для MAEST, MERT и CLAP подчиняется одному правилу: <code>auto</code> выбирает CUDA, когда PyTorch видит GPU, иначе CPU; явный <code>cuda</code> завершается ошибкой, если CUDA недоступна. Эти три семейства также используют батчинг инференса через <code>--inference-batch-size</code>; батчинг декодированных треков управляется отдельно через <code>--track-batch-size</code>. Группы установки <code>ml</code> и <code>sonara</code> описаны в разделе <a href="./install.html">Установка</a>.</p><h2 id="sonara" tabindex="-1">Sonara <a class="header-anchor" href="#sonara" aria-label="Permalink to &quot;Sonara&quot;">​</a></h2><p>Sonara — это быстрый объяснимый проход извлечения признаков. Общий загрузчик аудио начинает с <code>sonara.analyze_file</code>, а приложение сохраняет сфокусированный набор признаков плейлиста в <code>metadata_json.sonara_features</code> плюс имя модели в <code>metadata_json.sonara_model</code>.</p><p>Она выдаёт сгруппированные, понятные человеку признаки: основные сводки по ритму/громкости/спектру, перцептивные значения (<code>energy</code>, <code>danceability</code>, <code>valence</code>, <code>acousticness</code>), музыкальную тональность с уверенностью и тональный анализ. BPM и тональность Sonara — это проанализированные значения, а не скопированные теги файла, и приложение хранит исходные данные тональности Sonara, не выводя нотацию Camelot.</p><p>Как приложение это использует:</p><ul><li>Вкладка поиска SONARA ранжирует треки по этим признакам с настраиваемыми весами микшера и модификаторами.</li><li>Поля уровня библиотеки, такие как проанализированные BPM, тональность, energy, danceability и громкость, берутся из Sonara.</li><li>Признаки Sonara — один из входов для оценки продвинутыми классификаторами.</li></ul><p>Sonara работает на CPU и участвует в общих батчах декодированных треков, которые задаются <code>track_batch_size</code>; она не использует neural inference batch. Запустите Sonara первой, если не уверены, с чего начать; это самое прозрачное семейство, потому что UI может напрямую показывать и микшировать её группы признаков. Полный список ключей см. в разделе <a href="./analysis.html">Анализ</a>.</p><h2 id="maest" tabindex="-1">MAEST <a class="header-anchor" href="#maest" aria-label="Permalink to &quot;MAEST&quot;">​</a></h2><p>MAEST предсказывает жанровые метки и сохраняет embedding MAEST. Адаптер использует <code>maest-infer</code> с моделью <code>discogs-maest-30s-pw-129e-519l</code>.</p><p>Она анализирует до трёх 30-секундных окон на трек (около 60-секундного смещения, около 38% длительности и около 72% длительности). Невозможные или дублирующиеся окна ограничиваются и дедуплицируются. Активации по меткам усредняются по окнам для выбора верхних меток, а строки embedding MAEST усредняются по тем же окнам.</p><p>Она записывает только в SQLite:</p><ul><li><code>metadata_json.maest_model</code></li><li><code>metadata_json.maest_genres</code></li><li><code>metadata_json.maest_syncopated_rhythm</code></li><li>embedding под embedding key <code>maest</code></li></ul><p>Как приложение это использует:</p><ul><li>Сгенерированные жанровые метки поступают в диалог метаданных и необязательный рабочий процесс записи жанровых тегов.</li><li><code>maest_syncopated_rhythm</code> управляет библиотечным preset <code>syncopated</code>.</li><li>Embedding MAEST — вход для оценки продвинутыми классификаторами.</li></ul><p>Сам анализ MAEST никогда не изменяет аудио. Сохранение меток в стандартные жанровые теги — это отдельное явное действие, описанное в <a href="./search-and-tags.html">Поиск и теги</a>.</p><h2 id="mert" tabindex="-1">MERT <a class="header-anchor" href="#mert" aria-label="Permalink to &quot;MERT&quot;">​</a></h2><p>MERT строит audio-to-audio embeddings под embedding key <code>mert</code>. Модель по умолчанию:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m-a-p/MERT-v1-95M</span></span></code></pre></div><p>Как приложение это использует:</p><ul><li>Вкладка поиска MERT находит треки, близкие к выбранным seed-трекам в пространстве embedding MERT.</li><li>Поиск MERT использует только векторы MERT; он не смешивает признаки Sonara или векторы CLAP.</li><li>Embeddings MERT — вход для оценки продвинутыми классификаторами.</li></ul><p>Результаты зависят от существующих embeddings MERT, поэтому только что просканированные треки должны быть проанализированы до того, как они появятся в полезных результатах MERT. Запускайте MERT, когда схожесть по seed-трекам важнее объяснимых элементов управления.</p><h2 id="clap" tabindex="-1">CLAP <a class="header-anchor" href="#clap" aria-label="Permalink to &quot;CLAP&quot;">​</a></h2><p>CLAP строит ориентированные на музыку аудио-embeddings под embedding key <code>clap</code> и также может встраивать текст в то же пространство для text-to-audio search. Активный чекпойнт:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lukewys/laion_clap/music_audioset_epoch_15_esc_90.14.pt</span></span></code></pre></div><p>Как приложение это использует:</p><ul><li>Вкладка текстового поиска CLAP встраивает текстовый prompt и ранжирует относительно него аудиовекторы CLAP.</li><li>CLI-команда <code>dj-sim text-search</code> делает то же самое из терминала.</li><li>Текстовый поиск требует аудио-embeddings CLAP, созданных тем же чекпойнтом.</li></ul><p>Запускайте CLAP, когда хотите искать по настроению, инструментовке, энергии или другому описательному языку. Чёткие, конкретные prompts обычно работают лучше, чем одно жанровое слово.</p><h2 id="продвинутые-классификаторы" tabindex="-1">Продвинутые классификаторы <a class="header-anchor" href="#продвинутые-классификаторы" aria-label="Permalink to &quot;Продвинутые классификаторы&quot;">​</a></h2><p>Продвинутые классификаторы — это не модели анализа аудио; это локальные профили, обученные в Rhythm Lab, которые оценивают треки по уже сохранённым данным SONARA, MERT и MAEST. Поскольку они читают существующий анализ, а не декодируют аудио, сначала запустите Sonara, MERT и MAEST для треков, которые хотите оценить. Подробности об оценке см. в разделе <a href="./analysis.html">Анализ</a>, а об обучении и продвижении — в <a href="./rhythm-lab.html">Rhythm Lab</a>.</p>',35)])])}const u=a(c,[["render",s]]);export{m as __pageData,u as default};
